import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import "../App.css";
import Nav from "../components/Nav";
import API from "../api/axios";

export default function ContactPage() {

  /* =============================
     FORM STATE
  ============================= */

  const [formData, setFormData] = useState({
    name: "",
    email: "",
    message: ""
  });

  const [contactStatus, setContactStatus] = useState("");

  /* =============================
     THEME IMAGE SWITCHING
  ============================= */

  const updateThemeImages = () => {

    const theme = localStorage.getItem("user-theme");

    document.querySelectorAll(".theme-img").forEach(img => {

      if (theme === "dark" && img.dataset.dark) {
        img.src = img.dataset.dark;
      }

      if (theme === "light" && img.dataset.light) {
        img.src = img.dataset.light;
      }

    });
  };

  /* =============================
     LOAD THEME
  ============================= */

  useEffect(() => {

  const applyTheme = () => {

    const savedTheme = localStorage.getItem("user-theme");

    if (savedTheme === "dark") {
      document.body.classList.add("dark-mode");
    } else {
      document.body.classList.remove("dark-mode");
    }

    /* ✅ Force React-safe image swap */
    document.querySelectorAll(".theme-img").forEach(img => {

      if (savedTheme === "dark" && img.dataset.dark) {
        img.src = img.dataset.dark;
      }

      if (savedTheme === "light" && img.dataset.light) {
        img.src = img.dataset.light;
      }

    });

  };

  applyTheme();

  /* Listen theme change across pages */
  window.addEventListener("storage", applyTheme);

  return () => window.removeEventListener("storage", applyTheme);

}, []);

  /* =============================
     INPUT CHANGE
  ============================= */

  const handleChange = (e) => {

    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });

  };

  /* =============================
     FORM SUBMIT
  ============================= */

  const handleContactSubmit = (e) => {

    e.preventDefault();

    if (!formData.name || !formData.email || !formData.message) {
      setContactStatus("⚠️ Please fill in all fields");
      return;
    }

    if (!formData.email.includes("@")) {
      setContactStatus("⚠️ Please enter a valid email");
      return;
    }

    if (formData.message.length < 10) {
      setContactStatus("⚠️ Message must be at least 10 characters");
      return;
    }

    setContactStatus("Message sent successfully!");

    setFormData({
      name: "",
      email: "",
      message: ""
    });

    setTimeout(() => setContactStatus(""), 3000);
  };

  /* =============================
     UI RENDER
  ============================= */

  return (
    <>
      <Nav />

      <main className="content-wrapper">

        {/* CONTACT SECTION */}
        <section className="contact-hero">

          <div className="contact-form-container highlights">

            <h2>Get In Touch!</h2>

            <form noValidate onSubmit={handleContactSubmit}>

              <div className="input-group">
                <label>Name:</label>
                <input
                  name="name"
                  type="text"
                  placeholder="Enter your full name..."
                  value={formData.name}
                  onChange={handleChange}
                />
              </div>

              <div className="input-group">
                <label>Email:</label>
                <input
                  name="email"
                  type="email"
                  placeholder="user@email.com"
                  value={formData.email}
                  onChange={handleChange}
                />
              </div>

              <div className="input-group">
                <label>Message:</label>
                <textarea
                  name="message"
                  placeholder="Write your message here..."
                  value={formData.message}
